const CYCLE_INTERVAL = 4000;
const FADE_DURATION = 300;

function useCyclingPlaceholder(
  placeholders: string[] | undefined,
  isActive: boolean,
): string | undefined {
  const [index, setIndex] = useState(0);
  const [visible, setVisible] = useState(true);

  useEffect(() => {
    if (!placeholders || placeholders.length <= 1 || !isActive) {
      setIndex(0);
      setVisible(true);
      return;
    }

    const interval = setInterval(() => {
      setVisible(false);
      setTimeout(() => {
        setIndex(prev => (prev + 1) % placeholders.length);
        setVisible(true);
      }, FADE_DURATION);
    }, CYCLE_INTERVAL);

    return () => clearInterval(interval);
  }, [placeholders, isActive]);

  if (!placeholders || placeholders.length === 0) return undefined;
  return placeholders[index % placeholders.length];
}

export function SearchBar({
  value,
  onChange,
  placeholder = 'Search...',
  cyclingPlaceholders,
  activeDescendantId,
  breadcrumbs,
  dropdown,
}: SearchBarProps) {
  const inputRef = useRef<HTMLInputElement>(null);
  const isEmpty = !value;
  const cyclingText = useCyclingPlaceholder(cyclingPlaceholders, isEmpty);
  const [placeholderVisible, setPlaceholderVisible] = useState(true);

  useEffect(() => {
    if (!cyclingPlaceholders || cyclingPlaceholders.length <= 1 || !isEmpty) {
      setPlaceholderVisible(true);
